1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Empty / simplest cases ---
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Base premiums per main item type ---
15	  it.todo("single plain sword → premium 105 G (100 base + 5 fee)");
16	  it.todo("single plain amulet → premium 65 G (60 base + 5 fee)");
17	  it.todo("single plain staff → premium 85 G (80 base + 5 fee)");
18	  it.todo("single plain potion → premium 45 G (40 base + 5 fee)");
19	
20	  // --- Components ---
21	  it.todo("2 runes → 50 G base premium (+5 fee = 55)");
22	  it.todo("3 runes → 60 G base premium (block applies) (+5 fee = 65)");
23	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3) (+5 fee = 105)");
24	  it.todo("7 runes → 175 G base premium (+5 fee = 180)");
25	
26	  // --- 'Alike' clarification ---
27	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types) (+5 fee = 80)");
28	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks) (+5 fee = 125)");
29	
30	  // --- Item-specific modifiers ---
31	  it.todo("single cursed sword (steel, ench 3), newcomer first contract → 165 G");
32	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
33	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
34	  it.todo("cursed sword with enchantment 5 → both surcharges apply");
35	
36	  // --- Policy-wide modifiers ---
37	  it.todo("customer with exactly 2 years → loyalty discount applies");
38	
39	  // --- Modifier scope on multi-item policy ---
40	  it.todo("cursed sword + plain amulet → 210 G before further modifiers/fee (cursed surcharge on cursed item only)");
41	
42	  // --- Rounding ---
43	  it.todo("premium calculation that yields 197.5 G → final premium 198 G (rounded up in MHPCO's favor)");
44	
45	  // --- Integration examples ---
46	  it.todo("newcomer with cursed sword (steel, ench 3) → 165 G");
47	  it.todo("long-standing customer's second contract — cursed sword (steel, ench 7), 3 years → 160 G");
48	
49	  // --- Claim: standard reimbursement ---
50	  it.todo("regular sword damage 500 G → payout 400 G (full minus deductible)");
51	  it.todo("rune damage 200 G → payout 100 G (no special clause, deductible)");
52	
53	  // --- Claim: deductible per damage event ---
54	  it.todo("dragon attack damages sword (500 G) and amulet (300 G) → payout 600 G (deductible per item)");
55	
56	  // --- Claim: enchantment vs dragon material ---
57	  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50 % wins, then deductible)");
58	  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (dragon-material: full minus deductible)");
59	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50 % then deductible)");
60	  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (high-ench applies, then deductible)");
61	
62	  // --- Multiple items of same type ---
63	  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G; dragon attack damages both with separate deductibles");
64	  it.todo("damages contains more entries of a type than policy covers → CLI exits non-zero");
65	
66	  // --- Cap exhaustion ---
67	  it.todo("policy: sword + amulet → insurance sum 1600 G (cap 3200 G)");
68	  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
69	  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block affects premium only)");
70	  it.todo("sword, two successive claims of 1500 G each → first payout 1400 G, second 600 G; cap exhausted");
71	
72	  // --- Payout rounding ---
73	  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");
74	
75	  // --- Edge case errors ---
76	  it.todo("quote with unknown item type → CLI exits non-zero with stderr error; no results on stdout");
77	  it.todo("claim references damage for item not in policy → CLI exits non-zero with stderr error");
78	  it.todo("claim has negative damage amount → CLI exits non-zero with stderr error");
79	});
